8592     return false;
8593 
8594   if (B == C)
8595     return Pred1 == ICmpInst::getInversePredicate(Pred2);
8596 
8597   // Try to infer the relationship from constant ranges.
8598   const APInt *RHSC1, *RHSC2;
8599   if (!match(B, m_APInt(RHSC1)) || !match(C, m_APInt(RHSC2)))
