8718 static SelectPatternResult matchSelectPattern(CmpInst::Predicate Pred,
8719                                               FastMathFlags FMF,
8720                                               Value *CmpLHS, Value *CmpRHS,
8721                                               Value *TrueVal, Value *FalseVal,
8722                                               Value *&LHS, Value *&RHS,
8723                                               unsigned Depth) {
