8726     // IEEE-754 ignores the sign of 0.0 in comparisons. So if the select has one
8727     // 0.0 operand, set the compare's 0.0 operands to that same value for the
8728     // purpose of identifying min/max. Disregard vector constants with undefined
8729     // elements because those can not be back-propagated for analysis.
8730     Value *OutputZeroVal = nullptr;
8731     if (match(TrueVal, m_AnyZeroFP()) && !match(FalseVal, m_AnyZeroFP()) &&
8732         !cast<Constant>(TrueVal)->containsUndefOrPoisonElement())
8733       OutputZeroVal = TrueVal;
8734     else if (match(FalseVal, m_AnyZeroFP()) && !match(TrueVal, m_AnyZeroFP()) &&
8735              !cast<Constant>(FalseVal)->containsUndefOrPoisonElement())
8736       OutputZeroVal = FalseVal;
8737 
8738     if (OutputZeroVal) {
8739       if (match(CmpLHS, m_AnyZeroFP()) && CmpLHS != OutputZeroVal) {
8740         HasMismatchedZeros = true;
