296 
297   APInt MinValue = APInt::getSignedMinValue(BitWidth);
298   APInt MaxValue = APInt::getSignedMaxValue(BitWidth);
299   // e.g. Returning [-127, 127], represented as [-127, -128).
300   if (V.isAllOnes())
